scwin.sbm_save_submitdone = async function (e) {
    console.log("▷ sbm_save_submitdone (저장 submitdone)");

    if( e.responseJSON.resultDataSet[0].Code != 0 ) return;

// <!-- 저장 DataSet --> 
// language=JavaScript for=tr_save event=OnSuccess()>
	await $c.gus.cfAlertMsg("성공적으로 처리되었습니다" );	// 성공적으로삭제하였습니다
	// ds_salary.ClearData();
    ds_salary.setJSON([]);
	scwin.f_Retrieve();
};


//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function(e){
    console.log("=== f_Delete (삭제) ==================================================");
//체크

	// if(ds_salary.isUpdated==false){
    if( ds_salary.getModifiedIndex().length == 0 ) {
	 	await $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_056,"데이타"));
	 	return;
	}

	// 회계처리가 되었을때 체크
	for (i=0; i< ds_salary.getTotalRow() ; i++){
		if( ds_salary.getCellData(i,"salPayClsCd") =="C" || ds_salary.getCellData(i,"salPayClsCd") =="H"){  // OD지원금이나 통신비지원금은 원가전표를 만들지 않으므로 체크에서 뺀다.
			// if(  ds_salary.RowStatus(i)==3 &&  (ds_salary.NameValue(i,"outbrPostDt")!="" || ds_salary.NameValue(i,"payPostDt")!="") ){
            // 가우스 :     0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
            // 웹스퀘어 :   R:초기상태, U:갱신, C:삽입, D:삭제, V:삽입 후 삭제
            if(  // ds_salary.RowStatus(i)==3
                 ds_salary.getRowStatus(i)=="U" &&  (ds_salary.getCellData(i,"outbrPostDt")!="" ||
                 ds_salary.getCellData(i,"payPostDt")!="") ) {
				await $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_041,"전표번호(원가)["+ds_salary.getCellData(i,"outbrSlipNo")+"]","삭제를 "));
				return;
			}
		}

        // 가우스 SysStatus - 0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
        // - dlt_dataList1.getRowStatus(0);
        //    rowIndex 행의 상태코드를 문자로 반환 (R:초기상태, U:갱신, C:삽입, D:삭제, V:삽입 후 삭제)
        // - dlt_dataList1.getRowStatusValue(0);
        //    rowIndex 행의 상태코드를 숫자로 반환 (0:초기상태, 1:갱신, 2:삽입, 3:삭제, 4:삽입 후 삭제)

		if( ds_salary.getCellData(i,"salPayClsCd") !="C" || ds_salary.getCellData(i,"salPayClsCd") !="H"){ // OD지원금이나 통신비지원금이 아닌경우는 원래 체크로직을 탄다.
			if(
                //  ds_salary.getCellData(i)==3 &&
                 ds_salary.getRowStatus(i)=="U" &&
                 ds_salary.getCellData(i,"outbrSlipNo")!="0000000000" &&
                (ds_salary.getCellData(i,"outbrPostDt")!="" ||
                 ds_salary.getCellData(i,"payPostDt")!="") ) {
				await $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_041,"전표번호(원가)["+ds_salary.getCellData(i,"outbrSlipNo")+"]","삭제를 "));
				return;
			}
		}
	}

	// if(cfConfirmMsg(MSG_CM_CRM_008,Array("선택하신 전표"))==true){	
    let rtn2 = await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_008,"선택하신 전표"));
    if ( rtn2 ) {
		// tr_delete.Action="/ac.fi.gnrlaccount.slipmgnt.DeleteSalaryWorkSlipCMD.do";
		// tr_delete.Post();
        $c.sbm.execute(sbm_delete);
	}
};

