    console.log("▷ sbm_delete_submitdone (전표생성 submitdone)");

    if( e.responseJSON.resultDataSet[0].Code != 0 ) return;

// <!-- 삭제 DataSet --> 
// language=JavaScript for=tr_delete event=OnSuccess()>
	await $c.gus.cfAlertMsg(MSG_CM_INF_004 );	// 성공적으로삭제하였습니다
	ds_salary.setJSON([]);
	scwin.f_Retrieve();
};



